div.style:
padding: 1.25rem;
display: flex;
flex-direction: column;
gap: 0.75rem;
height: 100%;
overflow: hidden;
background: var(--o-view-background-color, #f8f9fa);

background: #ffffff;
border: 0.5px solid #dee2e6;
border-radius: 12px;
padding: 1rem 1.25rem;
display: flex;
align-items: stretch;
gap: 1.25rem;
flex-shrink: 0;

select.style:
font-size:14px;
box-shadow:none;
background:transparent;
padding-left:26px;
padding-right:24px;
appearance:none;
-webkit-appearance:none;
width:100%;
cursor:pointer;

font-size:12px;
color:#6c757d;
box-shadow:none;
background:transparent;
padding-left:26px;
padding-right:24px;
appearance:none;
-webkit-appearance:none;
width:100%;
cursor:pointer;

font-size:12px;
color:#6c757d;
box-shadow:none;
background:transparent;
padding-left:26px;
padding-right:24px;
appearance:none;
-webkit-appearance:none;
width:100%;
cursor:pointer;

div.style:
background:#fff5f5;
border:0.5px solid #f5c2c7;
border-radius:8px;
padding:0.75rem 1rem;
display:flex;flex-direction:column;align-items:center;justify-content:center;
min-width:120px;gap:2px;

div.t-attf-style:
width: {{has_sub ? '215px' : '155px'}};
display:flex;flex-direction:column;
background:#ffffff;
border:0.5px solid #dee2e6;
border-radius:12px;
overflow:hidden;
border-top:3px solid {{st_color}};
height:100%;

display:inline-flex;align-items:center;gap:3px;
font-size:10px;font-weight:500;border-radius:99px;
padding:2px 8px;
background:{{stage.status === 'done' ? '#d1e7dd' : stage.status === 'process' ? '#cfe2ff' : '#f8f9fa'}};
color:{{stage.status === 'done' ? '#0a3622' : stage.status === 'process' ? '#084298' : '#6c757d'}};
border:0.5px solid {{stage.status === 'done' ? '#a3cfbb' : stage.status === 'process' ? '#9ec5fe' : '#dee2e6'}};

height:100%;border-radius:99px;
background:{{st_color}};
width:{{stage.status === 'done' ? '100' : stage.status === 'process' ? (stage.code === 'registrasi' ? getRegistrasiPct(stage) : '30') : '0'}}%;
transition:width 0.6s;

position:absolute;left:-2px;top:5px;
width:7px;height:7px;border-radius:50%;
background:{{detail.is_done ? '#198754' : '#ffffff'}};
border:1.5px solid {{detail.is_done ? '#198754' : '#dee2e6'}};
outline:1px solid {{detail.is_done ? '#198754' : '#dee2e6'}};

span.t-attf-style:
font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary and stage.sub_summary.brand.total > 0 ? '#FAEEDA' : '#f8f9fa'}};
color:{{stage.sub_summary and stage.sub_summary.brand.total > 0 ? '#633806' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary and stage.sub_summary.brand.total > 0 ? '#EF9F27' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary and stage.sub_summary.nie.total > 0 ? '#E6F1FB' : '#f8f9fa'}};
color:{{stage.sub_summary and stage.sub_summary.nie.total > 0 ? '#0C447C' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary and stage.sub_summary.nie.total > 0 ? '#378ADD' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary and stage.sub_summary.halal.total > 0 ? '#EAF3DE' : '#f8f9fa'}};
color:{{stage.sub_summary and stage.sub_summary.halal.total > 0 ? '#27500A' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary and stage.sub_summary.halal.total > 0 ? '#639922' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.pr.total > 0 ? '#ede9ff' : '#f8f9fa'}};
color:{{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.pr.total > 0 ? '#3b1fa8' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.pr.total > 0 ? '#7048e8' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.po.total > 0 ? '#cfe2ff' : '#f8f9fa'}};
color:{{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.po.total > 0 ? '#084298' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.po.total > 0 ? '#0d6efd' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.delivered.total > 0 ? '#d1e7dd' : '#f8f9fa'}};
color:{{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.delivered.total > 0 ? '#0a3622' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary_pengadaan and stage.sub_summary_pengadaan.delivered.total > 0 ? '#198754' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary_delivery and stage.sub_summary_delivery.picking.total > 0 ? '#fce4ec' : '#f8f9fa'}};
color:{{stage.sub_summary_delivery and stage.sub_summary_delivery.picking.total > 0 ? '#7d1a4a' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary_delivery and stage.sub_summary_delivery.picking.total > 0 ? '#d63384' : '#dee2e6'}};

font-size:10px;padding:1px 6px;border-radius:99px;font-weight:500;
background:{{stage.sub_summary_delivery and stage.sub_summary_delivery.retur.total > 0 ? '#f8d7da' : '#f8f9fa'}};
color:{{stage.sub_summary_delivery and stage.sub_summary_delivery.retur.total > 0 ? '#842029' : '#6c757d'}};
border:0.5px solid {{stage.sub_summary_delivery and stage.sub_summary_delivery.retur.total > 0 ? '#dc3545' : '#dee2e6'}};
